package org.apache.commons.csv;

import org.junit.jupiter.api.Test;

import static org.junit.jupiter.api.Assertions.assertEquals;

public class CSVFormatTest {

    @Test
    public void testWithIgnoreHeaderCase() throws Exception {
        // Given
        CSVFormat csvFormat = CSVFormat.DEFAULT;

        // When
        CSVFormat result = invokePrivateMethod(csvFormat, "withIgnoreHeaderCase");

        // Then
        assertEquals(true, result.getIgnoreHeaderCase());
    }

    // Helper method to invoke private methods using reflection
    private <T> T invokePrivateMethod(Object object, String methodName, Object... args) throws Exception {
        java.lang.reflect.Method method = object.getClass().getDeclaredMethod(methodName);
        method.setAccessible(true);
        return (T) method.invoke(object, args);
    }
}
